-- 0249_import_apricus_stores.sql
-- Import the Apricus Little Caesars stores (brand=little_caesars, company=apricus).
-- Idempotent upsert on (company_id, number). Hierarchy null; lat/long null
-- (Phase 3 geocodes). Store 0050 (no address) skipped. Belton MO uses temp
-- number 0000 (0074 collided with Andalusia AL) — update later.
-- 64 stores imported; 1 skipped: 0050 Westnedge (no address).

on conflict (company_id, number) do update set
  name = excluded.name, address = excluded.address, state = excluded.state,
  zip = excluded.zip, brand = excluded.brand, brand_meta = excluded.brand_meta, is_active = true;

notify pgrst, 'reload schema';
